    const overlay = document.getElementById('bottom-submenuOverlay');

    // Close other submenus
    document.querySelectorAll('.bottom-submenu').forEach(menu => {
        if (menu.id !== menuId) menu.classList.remove('active');
    });

    $('html').addClass('scroll-hide-sm'); 

    submenu.classList.toggle('active');
    overlay.classList.toggle('active');
}

document.addEventListener('DOMContentLoaded', () => {
    const bottomNavButtons = document.querySelectorAll('.bottom-nav-item'); 
    bottomNavButtons.forEach(button => {
        button.addEventListener('click', (event) => {
            const btn = event.currentTarget;
            const url = btn.getAttribute('data-url');
            const menuID = btn.getAttribute('data-menuID');
            if (url) {
                window.open(url, '_self');
            } else if (menuID) {
                toggleSubmenu(menuID);
            }
        });
    });
});
